# ── API Login Steps ───────────────────────────────────────────────────────

@when('a POST request is sent to the login endpoint')
def step_prepare_login_request(context):
    """Prepare login API request."""
    base_url = os.getenv('BASE_URL', 'http://192.168.10.124:4001')
    context.login_url = f"{base_url}/login"
    context.request_body = {}


@when('the request includes valid username')
def step_add_valid_username(context):
    """Add valid username to request body."""
    creds = context.login_page.get_credentials_by_role('Admin')
    context.request_body['username'] = creds['username']
    context.request_body['email'] = creds['username']


@when('the request includes valid password')
def step_add_valid_password(context):
    """Add valid password to request body."""
    creds = context.login_page.get_credentials_by_role('Admin')
    context.request_body['password'] = creds['password']


@when('the request includes invalid username')
def step_add_invalid_username(context):
    """Add invalid username to request body."""
    context.request_body['username'] = 'invaliduser@example.com'
    context.request_body['email'] = 'invaliduser@example.com'


@when('the request includes invalid password')
def step_add_invalid_password(context):
    """Add invalid password to request body."""
    creds = context.login_page.get_credentials_by_role('Admin')
    context.request_body['username'] = creds['username']
    context.request_body['email'] = creds['username']
    context.request_body['password'] = 'WrongPassword123!'


@when('the request includes empty username field')
def step_add_empty_username(context):
    """Add empty username to request body."""
    context.request_body['username'] = ''
    context.request_body['email'] = ''


@when('the request includes empty password field')
def step_add_empty_password(context):
    """Add empty password to request body."""
    creds = context.login_page.get_credentials_by_role('Admin')
    context.request_body['username'] = creds['username']
    context.request_body['email'] = creds['username']
    context.request_body['password'] = ''


@when('the authentication request is submitted')
def step_submit_authentication_request(context):
    """Submit authentication request to API."""
    try:
        context.response = requests.post(
            context.login_url,
            json=context.request_body,
            headers={'Content-Type': 'application/json'},
            timeout=10
        )
    except requests.exceptions.RequestException as e:
        context.response = None
        context.request_error = str(e)


@then('the response should return {status_code:d} status code')
def step_verify_status_code(context, status_code):
    """Verify API response status code."""
    assert context.response is not None, f"Request failed: {getattr(context, 'request_error', 'Unknown error')}"
    assert context.response.status_code == status_code, \
        f"Expected {status_code}, got {context.response.status_code}. Response: {context.response.text}"


@then('the response should contain authentication token')
def step_verify_token_present(context):
    """Verify response contains authentication token."""
    response_json = context.response.json()
    assert 'token' in response_json or 'accessToken' in response_json or 'access_token' in response_json, \
        f"No token found in response: {response_json}"


@then('the error message should indicate invalid credentials')
def step_verify_invalid_credentials_error(context):
    """Verify error message indicates invalid credentials."""
    response_json = context.response.json()
    error_msg = str(response_json.get('error', response_json.get('message', ''))).lower()
    assert 'invalid' in error_msg or 'credentials' in error_msg or 'unauthorized' in error_msg, \
        f"Expected invalid credentials error, got: {response_json}"


@then('the error message should indicate missing username')
def step_verify_missing_username_error(context):
    """Verify error message indicates missing username."""
    response_json = context.response.json()
    error_msg = str(response_json.get('error', response_json.get('message', ''))).lower()
    assert 'username' in error_msg or 'email' in error_msg or 'required' in error_msg, \
        f"Expected missing username error, got: {response_json}"


@then('the error message should indicate missing password')
def step_verify_missing_password_error(context):
    """Verify error message indicates missing password."""
    response_json = context.response.json()
    error_msg = str(response_json.get('error', response_json.get('message', ''))).lower()
    assert 'password' in error_msg or 'required' in error_msg, \
        f"Expected missing password error, got: {response_json}"
